import Link from "next/link";
import { getRecords } from "../lib/records";
import { getServerSession } from "next-auth"; 
import { authOptions } from "../lib/auth"; 
import { redirect } from "next/navigation"; 

export default async function RecordsPage() {
  const session = await getServerSession(authOptions);
  if (!session) redirect("/login?callbackUrl=/records");

  const records = getRecords();

  return (
    <section className="container">
      <div className="row" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <div>
          <h1 style={{ margin: '0 0 8px 0' }}>ประวัติสุขภาพประจำวัน</h1>
          <p className="muted" style={{ margin: 0 }}>ผู้ใช้งาน: <b>{session.user?.name}</b></p>
        </div>
        <Link className="btn" href="/records/new">+ เช็กอินอาการ</Link>
      </div>

      <div className="grid">
        {records.map((record) => (
          <article key={record.id} className="card" style={{ borderLeft: `5px solid ${record.stressLevel >= 4 ? '#ef4444' : '#10b981'}` }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px' }}>
              <h3 style={{ margin: 0 }}>{record.date}</h3>
              <span style={{ background: '#f1f5f9', padding: '4px 10px', borderRadius: '20px', fontSize: '12px', fontWeight: 'bold' }}>
                ความเครียด: {record.stressLevel}/5
              </span>
            </div>

            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', marginBottom: '15px' }}>
              {record.neckPain && <span style={{ background: '#fee2e2', color: '#b91c1c', padding: '4px 8px', borderRadius: '4px', fontSize: '13px' }}>ปวดคอ/บ่า</span>}
              {record.backPain && <span style={{ background: '#fee2e2', color: '#b91c1c', padding: '4px 8px', borderRadius: '4px', fontSize: '13px' }}>ปวดหลัง</span>}
              {record.eyeStrain && <span style={{ background: '#fef3c7', color: '#b45309', padding: '4px 8px', borderRadius: '4px', fontSize: '13px' }}>ตาล้า</span>}
              {record.wristPain && <span style={{ background: '#fce7f3', color: '#be185d', padding: '4px 8px', borderRadius: '4px', fontSize: '13px' }}>ปวดข้อมือ</span>}
              {record.tookBreaks && <span style={{ background: '#d1fae5', color: '#047857', padding: '4px 8px', borderRadius: '4px', fontSize: '13px' }}>ได้ยืดเส้น</span>}
            </div>
            {record.note && <p className="muted" style={{ fontSize: '14px', fontStyle: 'italic' }}>"{record.note}"</p>}
          </article>
        ))}
      </div>
    </section>
  );
}